"use client"

import { Home, Search, Library, Settings, Heart, ListMusic, Radio, User } from "lucide-react"
import { cn } from "@/lib/utils"
import { useAuth } from "@/lib/auth-context"

interface SidebarProps {
  activeTab: string
  onTabChange: (tab: string) => void
}

const navItems = [
  { id: "home", icon: Home, label: "Головна" },
  { id: "search", icon: Search, label: "Пошук" },
  { id: "library", icon: Library, label: "Бібліотека" },
]

const libraryItems = [
  { id: "liked", icon: Heart, label: "Вподобані" },
  { id: "playlists", icon: ListMusic, label: "Плейлисти" },
  { id: "radio", icon: Radio, label: "Радіо" },
]

export function Sidebar({ activeTab, onTabChange }: SidebarProps) {
  const { user } = useAuth()
  
  return (
    <aside className="w-64 h-full flex flex-col bg-white/8 backdrop-blur-2xl border-r border-white/15 shadow-xl">
      {/* Logo */}
      <div className="p-6 flex items-center gap-3 border-b border-white/10">
        <div className="w-10 h-10 bg-gradient-to-br from-blue-400 to-purple-600 rounded-lg flex items-center justify-center shadow-lg">
          <span className="text-white text-lg font-bold">♪</span>
        </div>
        <span className="text-2xl font-bold text-white tracking-tight">AuroraTunes</span>
      </div>

      {/* Main Navigation */}
      <nav className="flex-1 p-4 space-y-2">
        {navItems.map((item) => (
          <button
            key={item.id}
            onClick={() => onTabChange(item.id)}
            className={cn(
              "w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all duration-300 font-medium",
              activeTab === item.id
                ? "bg-white/20 text-white shadow-lg backdrop-blur-md"
                : "text-white/70 hover:text-white hover:bg-white/10"
            )}
          >
            <item.icon className="w-5 h-5 shrink-0" />
            <span className="text-sm">{item.label}</span>
          </button>
        ))}

        <div className="py-4">
          <div className="h-px bg-white/10" />
        </div>

        <p className="px-4 text-xs text-white/50 uppercase tracking-widest font-semibold mb-3">
          Твоя музика
        </p>

        {libraryItems.map((item) => (
          <button
            key={item.id}
            onClick={() => onTabChange(item.id)}
            className={cn(
              "w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all duration-300 font-medium",
              activeTab === item.id
                ? "bg-white/20 text-white shadow-lg backdrop-blur-md"
                : "text-white/70 hover:text-white hover:bg-white/10"
            )}
          >
            <item.icon className="w-5 h-5 shrink-0" />
            <span className="text-sm">{item.label}</span>
          </button>
        ))}
      </nav>

      {/* Profile & Settings */}
      <div className="p-4 border-t border-white/10 space-y-2">
        <button
          onClick={() => onTabChange("profile")}
          className={cn(
            "w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all duration-300 font-medium",
            activeTab === "profile"
              ? "bg-white/20 text-white shadow-lg backdrop-blur-md"
              : "text-white/70 hover:text-white hover:bg-white/10"
          )}
        >
          {user?.avatar ? (
            <img src={user.avatar} alt="Avatar" className="w-5 h-5 rounded-full object-cover shrink-0" />
          ) : (
            <User className="w-5 h-5 shrink-0" />
          )}
          <span className="text-sm truncate">{user ? user.username : "Профіль"}</span>
        </button>
        <button
          onClick={() => onTabChange("settings")}
          className={cn(
            "w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all duration-300 font-medium",
            activeTab === "settings"
              ? "bg-white/20 text-white shadow-lg backdrop-blur-md"
              : "text-white/70 hover:text-white hover:bg-white/10"
          )}
        >
          <Settings className="w-5 h-5 shrink-0" />
          <span className="text-sm">Настройки</span>
        </button>
      </div>
    </aside>
  )
}
