"use client"

import { createContext, useContext, useState, useRef, useCallback, type ReactNode } from "react"
import type { Track } from "./types"

interface PlayerContextType {
  currentTrack: Track | null
  isPlaying: boolean
  progress: number
  volume: number
  currentTime: number
  duration: number
  playlist: Track[]
  setCurrentTrack: (track: Track | null) => void
  togglePlay: () => void
  setVolume: (volume: number) => void
  seek: (time: number) => void
  playTrack: (track: Track) => void
  setPlaylist: (tracks: Track[]) => void
  nextTrack: () => void
  prevTrack: () => void
  audioRef: React.RefObject<HTMLAudioElement | null>
}

const PlayerContext = createContext<PlayerContextType | null>(null)

export function PlayerProvider({ children }: { children: ReactNode }) {
  const [currentTrack, setCurrentTrack] = useState<Track | null>(null)
  const [isPlaying, setIsPlaying] = useState(false)
  const [progress, setProgress] = useState(0)
  const [volume, setVolumeState] = useState(0.7)
  const [currentTime, setCurrentTime] = useState(0)
  const [duration, setDuration] = useState(0)
  const [playlist, setPlaylist] = useState<Track[]>([])
  const audioRef = useRef<HTMLAudioElement | null>(null)
  const playPromiseRef = useRef<Promise<void> | null>(null)

  const togglePlay = useCallback(async () => {
    if (!audioRef.current) return
    
    if (isPlaying) {
      // Wait for any pending play promise before pausing
      if (playPromiseRef.current) {
        try {
          await playPromiseRef.current
        } catch {
          // Ignore errors from interrupted play
        }
        playPromiseRef.current = null
      }
      audioRef.current.pause()
      setIsPlaying(false)
    } else {
      try {
        playPromiseRef.current = audioRef.current.play()
        await playPromiseRef.current
        setIsPlaying(true)
      } catch (error) {
        // Ignore AbortError - it's expected when play is interrupted
        if (error instanceof Error && error.name !== 'AbortError') {
          console.error('Playback error:', error)
        }
      } finally {
        playPromiseRef.current = null
      }
    }
  }, [isPlaying])

  const setVolume = useCallback((vol: number) => {
    setVolumeState(vol)
    if (audioRef.current) {
      audioRef.current.volume = vol
    }
  }, [])

  const seek = useCallback((time: number) => {
    if (audioRef.current) {
      audioRef.current.currentTime = time
    }
  }, [])

  const playTrack = useCallback(async (track: Track) => {
    // Cancel any pending play operation
    if (playPromiseRef.current && audioRef.current) {
      try {
        await playPromiseRef.current
      } catch {
        // Ignore
      }
      audioRef.current.pause()
      playPromiseRef.current = null
    }
    
    setCurrentTrack(track)
    setIsPlaying(true)
    // In real app, would fetch stream URL from backend
    // For demo, we just set the track
  }, [])

  const nextTrack = useCallback(() => {
    if (!currentTrack || playlist.length === 0) return
    const currentIndex = playlist.findIndex(t => t.id === currentTrack.id)
    const nextIndex = (currentIndex + 1) % playlist.length
    playTrack(playlist[nextIndex])
  }, [currentTrack, playlist, playTrack])

  const prevTrack = useCallback(() => {
    if (!currentTrack || playlist.length === 0) return
    const currentIndex = playlist.findIndex(t => t.id === currentTrack.id)
    const prevIndex = currentIndex <= 0 ? playlist.length - 1 : currentIndex - 1
    playTrack(playlist[prevIndex])
  }, [currentTrack, playlist, playTrack])

  const handleTimeUpdate = useCallback(() => {
    if (audioRef.current) {
      const current = audioRef.current.currentTime
      const dur = audioRef.current.duration || 0
      setCurrentTime(current)
      setDuration(dur)
      setProgress(dur ? current / dur : 0)
    }
  }, [])

  const handleLoadedMetadata = useCallback(() => {
    if (audioRef.current) {
      setDuration(audioRef.current.duration)
    }
  }, [])

  return (
    <PlayerContext.Provider
      value={{
        currentTrack,
        isPlaying,
        progress,
        volume,
        currentTime,
        duration,
        playlist,
        setCurrentTrack,
        togglePlay,
        setVolume,
        seek,
        playTrack,
        setPlaylist,
        nextTrack,
        prevTrack,
        audioRef,
      }}
    >
      {children}
      <audio
        ref={audioRef}
        onTimeUpdate={handleTimeUpdate}
        onLoadedMetadata={handleLoadedMetadata}
        onEnded={() => setIsPlaying(false)}
      />
    </PlayerContext.Provider>
  )
}

export function usePlayer() {
  const context = useContext(PlayerContext)
  if (!context) {
    throw new Error("usePlayer must be used within PlayerProvider")
  }
  return context
}
